async function connectWallet(){
  if(userAddress) return;
  try {
    if(!window.ethereum) {
      showNotif('// install MetaMask or Coinbase Wallet', true);
      return;
    }

    // Use Web3Provider for ethers v5 (CDN version)
    provider = new ethers.providers.Web3Provider(window.ethereum, "any");

    const accounts = await provider.send('eth_requestAccounts', []);
    signer = provider.getSigner();
    userAddress = accounts[0];

    // Switch to Base
    try {
      await window.ethereum.request({
        method: 'wallet_switchEthereumChain',
        params: [{chainId: '0x2105'}]  // Base mainnet
      });
    } catch (switchError) {
      // Add Base if not present
      if(switchError.code === 4902) {
        await window.ethereum.request({
          method: 'wallet_addEthereumChain',
          params: [{
            chainId: '0x2105',
            chainName: 'Base',
            rpcUrls: ['https://mainnet.base.org'],
            nativeCurrency: {name: 'ETH', symbol: 'ETH', decimals: 18},
            blockExplorerUrls: ['https://basescan.org']
          }]
        });
      }
    }

    const short = userAddress.slice(0,6) + '...' + userAddress.slice(-4);
    const btn = document.getElementById('connectBtn');
    btn.textContent = short;
    btn.classList.add('connected');
    showNotif('// wallet connected — base mainnet');

  } catch(e) {
    console.error(e);
    showNotif('// connection rejected', true);
  }
}

// Make sure button has onclick handler
document.getElementById('connectBtn').onclick = connectWallet;

