  prompt: `Evaluate Polymarket trader:
    Win Rate: ${trader.win_rate}%
    Volume: $${trader.volume}
    Trades: ${trader.trades}

    Use structured reasoning to evaluate:
    1. Consistency over time
    2. Risk management
    3. Market selection quality
    4. Win rate sustainability

    Return: {score: 0-100, confidence: 0-1, reasoning: "...", recommendation: "BUY|PASS|REVIEW"}`,
  action
})

